{"path": "/tmp/sv-22fdd35e857f420d97c90f842275d89e/Components/Catalog/CatalogFilters.razor", "file_text": "<div class="p-3">
    <h5>Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-semibold">Categories</label>
        @if (Categories is not null)
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                           checked="@selectedCategories.Contains(category)"
                           @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Min Price</label>
        <input type="number" class="form-control" placeholder="0" min="0" step="0.01"
               @bind="minPrice" />
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Max Price</label>
        <input type="number" class="form-control" placeholder="Any" min="0" step="0.01"
               @bind="maxPrice" />
    </div>

    <div class="form-check mb-3">
        <input class="form-check-input" type="checkbox" id="inStockOnly"
               @bind="inStockOnly" />
        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public EventCallback<ProductFilter> OnFiltersApplied { get; set; }

    private HashSet<string> selectedCategories = [];
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );
        await OnFiltersApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        await OnFiltersApplied.InvokeAsync(new ProductFilter(null, null, null, false));
    }
}
"}

{"path": "/tmp/sv-22fdd35e857f420d97c90f842275d89e/Components/Catalog/CatalogToolbar.razor", "file_text": "<div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
    <div>
        <label class="form-label mb-0 me-2 fw-semibold">Sort by:</label>
        <select class="form-select d-inline-block w-auto" value="@SortBy" @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>
    <div class="text-muted">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            <span>Showing @start–@end of @TotalCount products</span>
        }
    </div>
</div>

@code {
    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}
"}

